254	  --------------------------------------------------------------------------
255	  -- Conversions between PSI and Enclustra Definitions
256	  --------------------------------------------------------------------------
257	  function psi_fix2_cl_fix(rnd : psi_fix_rnd_t)
258	  return FixRound_t is
259	  begin
260	    case rnd is
261	      when psi_fix_round => return NonSymPos_s;
262	      when psi_fix_trunc => return Trunc_s;
263	      when others => report "psi_fix_pkg: Unsupported Rounding Mode" severity error;
264	        return Trunc_s;
265	    end case;
266	  end function;
267	
268	  function psi_fix2_cl_fix(sat : psi_fix_sat_t)
269	  return FixSaturate_t is
270	  begin
271	    case sat is
272	      when psi_fix_sat  => return Sat_s;
273	      when psi_fix_wrap => return None_s;
274	      when others => report "psi_fix_pkg: Unsupported Saturation Mode" severity error;
275	        return None_s;
276	    end case;
277	  end function;
278	
279	  function psi_fix2_cl_fix(fmt : psi_fix_fmt_t)
280	  return FixFormat_t is
281	  begin
282	    return ((fmt.S = 1), fmt.I, fmt.F);
283	  end function;
284	
285	  function psi_fix2_cl_fix(fmts : psi_fix_fmt_array_t)
286	  return FixFormatArray_t is
287	    variable Fmts_v : FixFormatArray_t(fmts'range);
288	  begin
289	    for i in fmts'range loop
290	      Fmts_v(i) := psi_fix2_cl_fix(fmts(i));
291	    end loop;
292	    return Fmts_v;
293	  end function;
294	
295	  function cl_fix2_psi_fix(rnd : FixRound_t)
296	  return psi_fix_rnd_t is
297	  begin
298	    case rnd is
299	      when NonSymPos_s => return psi_fix_round;
300	      when Trunc_s     => return psi_fix_trunc;
301	      when others => report "psi_fix_pkg: Unsupported Rounding Mode (only Round/Trunc are supported)" severity error;
302	        return psi_fix_trunc;
303	    end case;
304	  end function;
305	
306	  function cl_fix2_psi_fix(sat : FixSaturate_t)
307	  return psi_fix_sat_t is
308	  begin
309	    case sat is
310	      when Sat_s  => return psi_fix_sat;
311	      when None_s => return psi_fix_wrap;
312	      when others => report "psi_fix_pkg: Unsupported Saturation Mode (only Sat/Wrap are supported)" severity error;
313	        return psi_fix_wrap;
314	    end case;
315	  end function;
316	
317	  function cl_fix2_psi_fix(fmt : FixFormat_t)
318	  return psi_fix_fmt_t is
319	  begin
320	    return (choose(fmt.Signed, 1, 0), fmt.Intbits, fmt.FracBits);
321	  end function;
322	
323	  function cl_fix2_psi_fix(fmts : FixFormatArray_t)
324	  return psi_fix_fmt_array_t is
325	    variable Fmts_v : psi_fix_fmt_array_t(fmts'range);
326	  begin
327	    for i in fmts'range loop
328	      Fmts_v(i) := cl_fix2_psi_fix(fmts(i));
329	    end loop;
330	    return Fmts_v;
331	  end function;
